declare(strict_types=1);require_once __DIR__.'/_layout.php';require_once dirname(__DIR__,2).'/includes/audit.php';exigirPermiso('academic.content.manage');if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf((string)($_POST['csrf_token']??''))){http_response_code(400);exit;}$pdo=obtenerConexion();$docenteId=docenteSupervisadoAtenea($pdo);$curso=docenteId($_POST['asignatura_id']??0);exigirCursoDocente($pdo,$docenteId,$curso);$titulo=trim(strip_tags((string)($_POST['titulo']??'')));$descripcion=trim(strip_tags((string)($_POST['descripcion']??'')));$estado=(string)($_POST['estado']??'borrador');if($titulo===''||mb_strlen($titulo)>190||mb_strlen($descripcion)>5000||!in_array($estado,['borrador','activo','inactivo'],true)){docenteFlash('error','Revisa los datos del contenido.');header('Location:'.docenteUrl('contenidos.php',['curso'=>$curso]));exit;}$archivo=[null,null,null,null];try{if(isset($_FILES['archivo'])&&$_FILES['archivo']['error']!==UPLOAD_ERR_NO_FILE){$f=$_FILES['archivo'];if($f['error']!==UPLOAD_ERR_OK||(int)$f['size']>10*1024*1024)throw new DomainException('El archivo no pudo recibirse o supera 10 MB.');$mime=(new finfo(FILEINFO_MIME_TYPE))->file($f['tmp_name']);$permitidos=['application/pdf'=>'pdf','application/msword'=>'doc','application/vnd.openxmlformats-officedocument.wordprocessingml.document'=>'docx','application/vnd.ms-powerpoint'=>'ppt','application/vnd.openxmlformats-officedocument.presentationml.presentation'=>'pptx','application/vnd.ms-excel'=>'xls','application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'=>'xlsx','image/jpeg'=>'jpg','image/png'=>'png'];if(!isset($permitidos[$mime])||preg_match('/\.(?:php\d*|phtml|phar|html?|svg)(?:\.|$)/i',(string)$f['name']))throw new DomainException('El tipo de archivo no está permitido.');$base=getenv('ACADEMIC_STORAGE_PATH')?:dirname(ATENEA_ROOT).'/atenea-private/academico';$dir=rtrim($base,'/\\').DIRECTORY_SEPARATOR.'contenidos';if(!is_dir($dir)&&!mkdir($dir,0700,true)&&!is_dir($dir))throw new RuntimeException('No se preparó el almacenamiento privado.');$nombre=bin2hex(random_bytes(20)).'.'.$permitidos[$mime];if(!move_uploaded_file($f['tmp_name'],$dir.DIRECTORY_SEPARATOR.$nombre))throw new RuntimeException('No se guardó el archivo.');$archivo=['contenidos/'.$nombre,mb_substr(basename((string)$f['name']),0,190),$mime,(int)$f['size']];}$q=$pdo->prepare('INSERT INTO contenidos(asignatura_id,docente_id,titulo,descripcion,archivo_relpath,archivo_nombre,archivo_mime,archivo_tamano,estado) VALUES(:a,:d,:t,:x,:r,:n,:m,:s,:e)');$q->execute(['a'=>$curso,'d'=>$docenteId,'t'=>$titulo,'x'=>$descripcion?:null,'r'=>$archivo[0],'n'=>$archivo[1],'m'=>$archivo[2],'s'=>$archivo[3],'e'=>$estado]);registrarAuditoria(['actor_user_id'=>$_SESSION['usuario_id'],'event_type'=>'academic.content.created','module'=>'academic','entity_type'=>'content','entity_id'=>$pdo->lastInsertId(),'action'=>'create','result'=>'success','description'=>'Contenido académico creado para un curso asignado.'], $pdo);docenteFlash('exito','Contenido guardado.');}catch(Throwable $e){docenteFlash('error',$e instanceof DomainException?$e->getMessage():'No fue posible guardar el contenido.');}header('Location:'.docenteUrl('contenidos.php',['curso'=>$curso]));
